import { createStore } from 'vuex'

export default createStore({
  state: {
    novels: [],
    currentNovel: null,
    processingStatus: null,
    loading: false,
    error: null
  },
  mutations: {
    SET_NOVELS(state, novels) {
      state.novels = novels
    },
    SET_CURRENT_NOVEL(state, novel) {
      state.currentNovel = novel
    },
    SET_PROCESSING_STATUS(state, status) {
      state.processingStatus = status
    },
    SET_LOADING(state, status) {
      state.loading = status
    },
    SET_ERROR(state, error) {
      state.error = error
    }
  },
  actions: {
    // 获取小说列表
    async fetchNovels({ commit }) {
      try {
        commit('SET_LOADING', true)
        // 实际项目中这里会调用API
        const response = await new Promise(resolve => {
          setTimeout(() => {
            resolve([
              { id: 1, title: '修真世界', author: '梦入神机', processedChapters: 10, totalChapters: 100 },
              { id: 2, title: '未来科技城', author: '星辰大海', processedChapters: 50, totalChapters: 50 }
            ])
          }, 500)
        })
        commit('SET_NOVELS', response)
        commit('SET_ERROR', null)
      } catch (error) {
        commit('SET_ERROR', '获取小说列表失败')
        console.error(error)
      } finally {
        commit('SET_LOADING', false)
      }
    },
    
    // 获取小说详情
    async fetchNovelDetail({ commit }, novelId) {
      try {
        commit('SET_LOADING', true)
        // 实际项目中这里会调用API
        const response = await new Promise(resolve => {
          setTimeout(() => {
            resolve({
              id: novelId,
              title: novelId == 1 ? '修真世界' : '未来科技城',
              author: novelId == 1 ? '梦入神机' : '星辰大海',
              description: novelId == 1 
                ? '一个普通少年偶然获得远古传承，逐步成长为修真界顶尖强者的故事。'
                : '2150年，人类建立了第一座智能城市，但随着AI的发展，一系列惊人的变故开始发生...',
              chapters: [
                { id: 1, chapterNumber: 1, title: novelId == 1 ? '山村少年' : '智能城市' },
                { id: 2, chapterNumber: 2, title: novelId == 1 ? '初习功法' : '系统异常' },
                { id: 3, chapterNumber: 3, title: novelId == 1 ? '山外世界' : '伦理学家' },
                { id: 4, chapterNumber: 4, title: novelId == 1 ? '修真界的历史' : '失控的开始' },
                { id: 5, chapterNumber: 5, title: novelId == 1 ? '初入青云门' : '阴谋浮现' }
              ]
            })
          }, 500)
        })
        commit('SET_CURRENT_NOVEL', response)
        commit('SET_ERROR', null)
      } catch (error) {
        commit('SET_ERROR', '获取小说详情失败')
        console.error(error)
      } finally {
        commit('SET_LOADING', false)
      }
    },
    
    // 上传小说
    async uploadNovel({ commit, state }) {
      try {
        commit('SET_LOADING', true)
        commit('SET_PROCESSING_STATUS', 'UPLOADING')
        
        // 模拟上传过程
        await new Promise(resolve => setTimeout(resolve, 1000))
        
        // 模拟处理过程
        commit('SET_PROCESSING_STATUS', 'PROCESSING')
        await new Promise(resolve => setTimeout(resolve, 2000))
        
        // 生成一个新的演示小说数据
        const demoNovel = {
          id: 3,
          title: '演示小说',
          author: '当前用户',
          description: '这是一个通过上传功能生成的演示小说。由于后端API尚未实现，这里展示的是模拟数据。在实际项目中，这里会展示从您上传的文件中提取的内容。',
          processedChapters: 10,
          totalChapters: 10,
          chapters: [
            { id: 1, chapterNumber: 1, title: '演示章节1' },
            { id: 2, chapterNumber: 2, title: '演示章节2' },
            { id: 3, chapterNumber: 3, title: '演示章节3' },
            { id: 4, chapterNumber: 4, title: '演示章节4' },
            { id: 5, chapterNumber: 5, title: '演示章节5' }
          ]
        }
        
        // 更新状态
        const novels = [...state.novels, demoNovel]
        commit('SET_NOVELS', novels)
        commit('SET_CURRENT_NOVEL', demoNovel)
        commit('SET_PROCESSING_STATUS', 'COMPLETED')
        
        // 返回小说ID (实际项目中这里会从API返回)
        return 3
      } catch (error) {
        commit('SET_ERROR', '上传小说失败')
        commit('SET_PROCESSING_STATUS', 'FAILED')
        console.error(error)
        throw error
      } finally {
        commit('SET_LOADING', false)
      }
    }
  },
  getters: {
    getNovelById: (state) => (id) => {
      return state.novels.find(novel => novel.id === id)
    },
    processingPercentage: (state) => {
      if (!state.processingStatus) return 0
      
      switch (state.processingStatus) {
        case 'UPLOADING': return 20
        case 'PROCESSING': return 60
        case 'COMPLETED': return 100
        case 'FAILED': return 0
        default: return 0
      }
    },
    isLoggedIn: () => {
      // 暂时模拟用户未登录状态
      return false
    }
  }
})
